/**
 * speak.ts — Voice readback extension for Pi
 *
 * When the agent finishes a turn, this extension:
 *   1. Fires a macOS notification (terminal-notifier or osascript fallback)
 *   2. Auto-plays the response via Unreal Speech TTS (only when the Pi window is not focused)
 *   3. Registers alt+r to replay / stop the last response
 *   4. Shows a status widget below the editor
 *
 * Settings (Unreal Speech V8):
 *   VoiceId: Sierra | Bitrate: 192k | Speed: 0 | Pitch: 1.0
 *
 * API key: read from ~/.env (UNREAL_SPEECH_API_KEY) or process.env
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { execSync, spawn, type ChildProcess } from "node:child_process";
import { readFileSync, unlinkSync, writeFileSync, existsSync } from "node:fs";
import { homedir, tmpdir } from "node:os";
import { resolve, join } from "node:path";

// ─── Platform abstraction ────────────────────────────────────────────────────

interface Platform {
  /** Send a system notification. If tmuxTarget is provided, clicking the notification
   *  should focus the terminal AND switch to the given tmux session:window. */
  notify(title: string, subtitle: string, message: string, tmuxTarget?: string): void;
  /** Play an MP3 file. The onProcess callback receives the ChildProcess so the caller
   *  can kill it to stop playback. Resolves when playback finishes. */
  playAudio(filePath: string, onProcess?: (proc: ChildProcess) => void): Promise<void>;
  /** Check if our terminal window is currently focused. */
  isFocused(myPaneId: string): boolean;
}

function createPlatform(): Platform {
  switch (process.platform) {
    case "darwin":
      return createMacOSPlatform();
    // Future: case "linux": return createLinuxPlatform();
    // Future: case "win32": return createWindowsPlatform();
    default:
      // Minimal fallback — no notifications, no focus detection
      return {
        notify: () => {},
        playAudio: async () => {},
        isFocused: () => true, // always assume focused → skip auto-play
      } as Platform;
  }
}

function createMacOSPlatform(): Platform {
  const hasTerminalNotifier = (() => {
    try {
      execSync("which terminal-notifier", { stdio: "pipe" });
      return true;
    } catch {
      return false;
    }
  })();

  return {
    notify(title, subtitle, message, tmuxTarget) {
      if (hasTerminalNotifier) {
        // Interactive notification — click activates Ghostty + switches tmux window
        let executeCmd = `osascript -e 'tell application "Ghostty" to activate'`;
        if (tmuxTarget) {
          executeCmd += `; tmux switch-client -t '${tmuxTarget}'`;
        }
        const cmd = [
          "terminal-notifier",
          "-title", shellQuote(title),
          "-subtitle", shellQuote(subtitle),
          "-message", shellQuote(message),
          "-execute", shellQuote(executeCmd),
          "-group", "pi-speak",
        ].join(" ");
        spawn("sh", ["-c", cmd], { stdio: "ignore", detached: true }).unref();
      } else {
        // Fallback: plain osascript notification (non-interactive)
        const notif = `display notification ${shellQuote(message)} with title ${shellQuote(title)} subtitle ${shellQuote(subtitle)}`;
        spawn("osascript", ["-e", notif], { stdio: "ignore", detached: true }).unref();
      }
    },

    async playAudio(filePath, onProcess) {
      return new Promise<void>((resolve, reject) => {
        const proc = spawn("afplay", [filePath], { stdio: "ignore" });
        if (onProcess) onProcess(proc);
        proc.on("close", (code) => {
          // code null means killed by signal — that's a user-initiated stop, not an error
          if (code === 0 || code === null) resolve();
          else reject(new Error(`afplay exited with code ${code}`));
        });
        proc.on("error", reject);
      });
    },

    isFocused(myPaneId) {
      try {
        // 1. Check if Ghostty is the frontmost app
        const frontmostApp = execSync(
          `osascript -e 'tell application "System Events" to get name of first application process whose frontmost is true'`,
          { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] },
        ).trim();

        if (frontmostApp !== "Ghostty") {
          return false; // Ghostty not focused → not watching
        }

        // 2. Ghostty is focused — check if our tmux pane is the active one
        if (!myPaneId || !process.env.TMUX) {
          return true; // Not in tmux, assume focused
        }

        const activePane = execSync(
          `tmux display-message -p -t '' '#{pane_id}'`,
          { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] },
        ).trim();

        return activePane === myPaneId;
      } catch {
        // If we can't determine focus, assume focused (skip auto-play)
        return true;
      }
    },
  };
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function shellQuote(s: string): string {
  return `'${s.replace(/'/g, "'\\''")}'`;
}

/** Load a key from ~/.env (simple KEY=VALUE parser, no dependency) */
function loadEnvKey(key: string): string | undefined {
  const envPath = join(homedir(), ".env");
  if (!existsSync(envPath)) return undefined;
  try {
    const contents = readFileSync(envPath, "utf-8");
    for (const line of contents.split("\n")) {
      const trimmed = line.trim();
      if (trimmed.startsWith("#") || trimmed.length === 0) continue;
      const eqIdx = trimmed.indexOf("=");
      if (eqIdx === -1) continue;
      const k = trimmed.slice(0, eqIdx).trim();
      let v = trimmed.slice(eqIdx + 1).trim();
      // Strip surrounding quotes
      if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) {
        v = v.slice(1, -1);
      }
      if (k === key) return v;
    }
  } catch {
    // ignore
  }
  return undefined;
}

/** Resolve the tmux session:window target for the given pane ID */
function resolveTmuxTarget(paneId: string): string | undefined {
  try {
    return execSync(
      `tmux display-message -p -t '${paneId}' '#{session_name}:#{window_index}'`,
      { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] },
    ).trim();
  } catch {
    return undefined;
  }
}

/** Strip markdown formatting for cleaner speech */
function stripMarkdown(text: string): string {
  return text
    // Remove code blocks
    .replace(/```[\s\S]*?```/g, (match) => {
      // Simplify code blocks — keep content but strip fences
      return match.replace(/```\w*\n?/g, "").trim();
    })
    // Remove inline code backticks
    .replace(/`([^`]+)`/g, "$1")
    // Remove bold/italic markers
    .replace(/\*{1,3}([^*]+)\*{1,3}/g, "$1")
    .replace(/_{1,3}([^_]+)_{1,3}/g, "$1")
    // Remove strikethrough
    .replace(/~~([^~]+)~~/g, "$1")
    // Remove links, keep text
    .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
    // Remove headers markers
    .replace(/^#{1,6}\s+/gm, "")
    // Remove horizontal rules
    .replace(/^---+$/gm, "")
    // Remove list markers
    .replace(/^\s*[-*+]\s+/gm, "")
    .replace(/^\s*\d+\.\s+/gm, "")
    // Collapse multiple whitespace
    .replace(/\n{2,}/g, "\n\n")
    .trim();
}

/** Split text into chunks at sentence boundaries, each ≤ maxChars */
function chunkBySentences(text: string, maxChars: number): string[] {
  const chunks: string[] = [];
  let current = "";

  // Split on sentence boundaries (., !, ?, followed by space or end)
  const sentences = text.split(/(?<=[.!?])\s+/);

  for (const sentence of sentences) {
    if (current.length === 0) {
      current = sentence;
    } else if (current.length + 1 + sentence.length <= maxChars) {
      current += " " + sentence;
    } else {
      chunks.push(current);
      current = sentence;
    }
  }

  if (current.length > 0) {
    chunks.push(current);
  }

  // If a single chunk exceeds maxChars (no sentence boundaries), hard-split at maxChars
  const result: string[] = [];
  for (const chunk of chunks) {
    if (chunk.length <= maxChars) {
      result.push(chunk);
    } else {
      // Hard split at word boundaries
      let remaining = chunk;
      while (remaining.length > 0) {
        if (remaining.length <= maxChars) {
          result.push(remaining);
          break;
        }
        let splitAt = remaining.lastIndexOf(" ", maxChars);
        if (splitAt === -1) splitAt = maxChars;
        result.push(remaining.slice(0, splitAt));
        remaining = remaining.slice(splitAt).trim();
      }
    }
  }

  return result;
}

/** Generate a one-line summary for notifications */
function summarize(text: string, maxLen = 80): string {
  const firstLine = text.split("\n")[0] ?? "";
  if (firstLine.length <= maxLen) return firstLine;
  return firstLine.slice(0, maxLen - 1) + "…";
}

// ─── Extension ───────────────────────────────────────────────────────────────

const MAX_CHUNK_CHARS = 900; // Leave room below Unreal Speech's 1000 char limit
const TEMP_FILE_PREFIX = "pi-speak-";

export default function (pi: ExtensionAPI) {
  const platform = createPlatform();

  // ── State ──────────────────────────────────────────────────────────────────

  let lastResponseText = "";
  let currentPlayback: ChildProcess | null = null;
  let isPlaying = false;
  let disabled = false;
  let myPaneId = "";
  let hasNotifiedTerminalNotifier = false;

  // ── TTS via Unreal Speech ─────────────────────────────────────────────────

  async function fetchTTS(text: string): Promise<Buffer> {
    const apiKey = process.env.UNREAL_SPEECH_API_KEY;
    if (!apiKey) throw new Error("UNREAL_SPEECH_API_KEY not set");

    const response = await fetch("https://api.v8.unrealspeech.com/stream", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        Text: text,
        VoiceId: "Sierra",
        Bitrate: "192k",
        Speed: 0,
        Pitch: 1.0,
      }),
    });

    if (!response.ok) {
      const body = await response.text();
      throw new Error(`Unreal Speech API error ${response.status}: ${body}`);
    }

    const arrayBuf = await response.arrayBuffer();
    return Buffer.from(arrayBuf);
  }

  async function speakText(text: string, ctx: any): Promise<void> {
    if (!text || disabled) return;

    isPlaying = true;
    updateWidget(ctx);

    const chunks = chunkBySentences(text, MAX_CHUNK_CHARS);
    const tempFiles: string[] = [];

    try {
      for (let i = 0; i < chunks.length; i++) {
        if (!isPlaying) break; // Stopped by user

        const mp3Data = await fetchTTS(chunks[i]!);
        const tmpFile = join(tmpdir(), `${TEMP_FILE_PREFIX}${Date.now()}-${i}.mp3`);
        tempFiles.push(tmpFile);
        writeFileSync(tmpFile, mp3Data);

        if (!isPlaying) break;

        await platform.playAudio(tmpFile, (proc) => { currentPlayback = proc; });
      }
    } catch (err: any) {
      if (isPlaying) {
        ctx.ui.notify(`speak: TTS error — ${err.message}`, "error");
      }
    } finally {
      isPlaying = false;
      currentPlayback = null;
      updateWidget(ctx);

      // Clean up temp files
      for (const f of tempFiles) {
        try {
          unlinkSync(f);
        } catch {
          // ignore
        }
      }
    }
  }

  function stopPlayback(): void {
    isPlaying = false;
    if (currentPlayback) {
      currentPlayback.kill("SIGTERM");
      currentPlayback = null;
    }
  }

  // ── Widget ────────────────────────────────────────────────────────────────

  function updateWidget(ctx: any): void {
    if (disabled) {
      ctx.ui.setWidget("speak", undefined);
      return;
    }
    if (isPlaying) {
      ctx.ui.setWidget("speak", ["🔊 Speaking…  alt+r stop"]);
    } else if (lastResponseText) {
      ctx.ui.setWidget("speak", ["🔊 Ready  alt+r replay"]);
    } else {
      ctx.ui.setWidget("speak", ["🔊 alt+r read aloud"]);
    }
  }

  // ── Extract assistant text ────────────────────────────────────────────────

  function extractAssistantText(messages: any[]): string {
    // Walk messages in reverse to find the last assistant message
    for (let i = messages.length - 1; i >= 0; i--) {
      const msg = messages[i];
      if (msg?.role !== "assistant") continue;

      const textParts: string[] = [];
      for (const block of msg.content ?? []) {
        if (block.type === "text" && typeof block.text === "string") {
          textParts.push(block.text);
        }
      }

      if (textParts.length > 0) {
        return stripMarkdown(textParts.join("\n"));
      }
    }
    return "";
  }

  // ─── Session start ────────────────────────────────────────────────────────

  pi.on("session_start", async (_event, ctx) => {
    // Capture tmux pane ID
    myPaneId = process.env.TMUX_PANE ?? "";

    // Load API key from ~/.env (fallback to process.env)
    if (!process.env.UNREAL_SPEECH_API_KEY) {
      const fromEnv = loadEnvKey("UNREAL_SPEECH_API_KEY");
      if (fromEnv) {
        process.env.UNREAL_SPEECH_API_KEY = fromEnv;
      }
    }

    if (!process.env.UNREAL_SPEECH_API_KEY) {
      disabled = true;
      ctx.ui.notify(
        "speak: UNREAL_SPEECH_API_KEY not set — voice readback disabled. Add it to ~/.env",
        "warning",
      );
      ctx.ui.setWidget("speak", undefined);
      return;
    }

    // Hint about terminal-notifier if not installed
    if (process.platform === "darwin" && !hasNotifiedTerminalNotifier) {
      try {
        execSync("which terminal-notifier", { stdio: "pipe" });
      } catch {
        hasNotifiedTerminalNotifier = true;
        ctx.ui.notify(
          "speak: Install terminal-notifier for clickable notifications: brew install terminal-notifier",
          "info",
        );
      }
    }

    updateWidget(ctx);
  });

  // ─── Agent end ─────────────────────────────────────────────────────────────

  pi.on("agent_end", async (event, ctx) => {
    if (disabled) return;

    const text = extractAssistantText(event.messages);
    if (!text) return;

    lastResponseText = text;
    updateWidget(ctx);

    // Resolve tmux target for the notification click action
    const tmuxTarget = myPaneId ? resolveTmuxTarget(myPaneId) : undefined;

    // Fire notification (always)
    const summary = summarize(text);
    platform.notify("Pi ✓", summary, "Click to focus session", tmuxTarget);

    // Auto-play only when the Pi window is not focused
    const focused = platform.isFocused(myPaneId);
    if (focused) return;

    // Start TTS playback (non-blocking)
    speakText(text, ctx);
  });

  // ─── Shortcut: alt+r — replay / stop ──────────────────────────────────────

  pi.registerShortcut("alt+r", {
    description: "Replay last response aloud / stop current playback",
    handler: (ctx) => {
      if (disabled) return;

      if (isPlaying) {
        stopPlayback();
        updateWidget(ctx);
        return;
      }

      if (!lastResponseText) {
        ctx.ui.notify("speak: no response to replay yet", "info");
        return;
      }

      speakText(lastResponseText, ctx);
    },
  });
}

