/** Delete all cached audio files */
function clearAudioCache(): void {
  for (const f of cachedAudioFiles) {
    try {
      unlinkSync(f);
    } catch {
      // ignore — file may already be gone
    }
  }
  cachedAudioFiles = [];
}

async function speakText(text: string, ctx: any): Promise<void> {
  if (!text || disabled) return;

  isPlaying = true;
  updateWidget(ctx);

  const chunks = chunkBySentences(text, MAX_CHUNK_CHARS);
  const newFiles: string[] = [];

  try {
    for (let i = 0; i < chunks.length; i++) {
      if (!isPlaying) break; // Stopped by user

      // Check if we already have a cached file for this chunk
      const existingFile = cachedAudioFiles[i];
      let playFile: string;

      if (existingFile && existsSync(existingFile)) {
        playFile = existingFile;
      } else {
        // Fetch and cache
        const mp3Data = await fetchTTS(chunks[i]!);
        playFile = join(tmpdir(), `${TEMP_FILE_PREFIX}${Date.now()}-${i}.mp3`);
        writeFileSync(playFile, mp3Data);
      }

      newFiles.push(playFile);

      if (!isPlaying) break;

      await platform.playAudio(playFile, (proc) => { currentPlayback = proc; });
    }
  } catch (err: any) {
    if (isPlaying) {
      ctx.ui.notify(`speak: TTS error — ${err.message}`, "error");
    }
  } finally {
    isPlaying = false;
    currentPlayback = null;

    // Replace cache with the files we just produced/used
    // Delete any old files that are no longer in the new set
    const oldFiles = cachedAudioFiles.filter((f) => !newFiles.includes(f));
    for (const f of oldFiles) {
      try {
        unlinkSync(f);
      } catch {
        // ignore
      }
    }
    cachedAudioFiles = newFiles;

    updateWidget(ctx);
  }
}

