      // Check if we already have a cached file for this chunk
      const existingFile = cachedAudioFiles[i];
      let playFile: string;

      if (existingFile && existsSync(existingFile)) {
        playFile = existingFile;
        debug(`speakText: gen=${myGeneration} chunk ${i}: CACHE HIT → ${playFile}`);
      } else {
        // Fetch and cache
        debug(`speakText: gen=${myGeneration} chunk ${i}: FETCHING from Unreal Speech...`);
        const mp3Data = await fetchTTS(chunks[i]!);
        // Re-check after async — another call may have started
        if (playGeneration !== myGeneration) {
          debug(`speakText: gen=${myGeneration} aborted after fetch at chunk ${i}`);
          break;
        }
        playFile = join(tmpdir(), `${TEMP_FILE_PREFIX}${Date.now()}-${i}.mp3`);
        writeFileSync(playFile, mp3Data);
        debug(`speakText: gen=${myGeneration} chunk ${i}: FETCHED → ${playFile} (${mp3Data.length} bytes)`);
      }

      newFiles.push(playFile);

      if (playGeneration !== myGeneration) break;

      await platform.playAudio(playFile, (proc) => { currentPlayback = proc; });
    }
  } catch (err: any) {
    if (playGeneration === myGeneration) {
      debug(`speakText: gen=${myGeneration} ERROR: ${err.message}`);
      ctx.ui.notify(`speak: TTS error — ${err.message}`, "error");
    }
  } finally {
    // Only update state if we're still the active generation
