        } catch {
          // ignore
        }
      }
      cachedAudioFiles = newFiles;
      debug(`speakText: gen=${myGeneration} done. cachedFiles=${cachedAudioFiles.length} path=${cachedAudioFiles[0] ?? "none"}`);

