  handler: (ctx) => {
    if (disabled) return;

    if (isPlaying) {
      // Stop current playback — but if there's cached audio, immediately replay
      stopPlayback();
      if (lastResponseText && cachedAudioFiles.length > 0 && cachedAudioFiles.every((f) => existsSync(f))) {
        // Cached files still on disk — instant replay
        speakText(lastResponseText, ctx);
      } else {
        updateWidget(ctx);
      }
      return;
    }

    if (!lastResponseText) {
      ctx.ui.notify("speak: no response to replay yet", "info");
      return;
    }

    speakText(lastResponseText, ctx);
  },
});

