  const hasTerminalNotifier = (() => {
    try {
      const path = execSync("which terminal-notifier", { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] }).trim();
      debug(`platform: terminal-notifier found at ${path}`);
      return true;
    } catch {
      debug("platform: terminal-notifier NOT found, falling back to osascript");
      return false;
    }
  })();

  return {
    notify(title, subtitle, message, tmuxTarget, paneId, shortcut) {
      debug(`notify: hasTerminalNotifier=${hasTerminalNotifier}`);
      debug(`notify: title="${title}" subtitle="${subtitle}"`);
      debug(`notify: message="${message}"`);
      debug(`notify: tmuxTarget=${tmuxTarget ?? "undefined"} paneId=${paneId ?? "undefined"} shortcut=${shortcut ?? "undefined"}`);
      debug(`notify: ignoreDnd=${ignoreDnd} group=${notificationGroup}`);

      if (hasTerminalNotifier) {
        // Interactive notification — click activates Ghostty + switches tmux window + sends shortcut key
        let executeCmd = `osascript -e 'tell application "Ghostty" to activate'`;
        if (tmuxTarget) {
          executeCmd += `; tmux switch-client -t '${tmuxTarget}'`;
          debug(`notify: -execute will switch to tmux target '${tmuxTarget}'`);
        } else {
          debug(`notify: no tmuxTarget — -execute will only activate Ghostty`);
        }
        // Send the shortcut key to the Pi pane to trigger readback
        if (paneId && shortcut) {
          const tmuxKey = shortcutToTmuxKey(shortcut);
          executeCmd += `; tmux send-keys -t '${paneId}' ${tmuxKey}`;
          debug(`notify: -execute will send tmux key '${tmuxKey}' to pane '${paneId}'`);
        } else {
          debug(`notify: paneId or shortcut missing — -execute will NOT send keys`);
        }

        const cmd = [
          "terminal-notifier",
          "-title", shellQuote(title),
          "-subtitle", shellQuote(subtitle),
          "-message", shellQuote(message),
          "-execute", shellQuote(executeCmd),
          "-group", notificationGroup,
        ];
        if (ignoreDnd) cmd.push("-ignoreDnD");
        const cmdStr = cmd.join(" ");
        debug(`notify: spawning: sh -c '${cmdStr}'`);
        const child = spawn("sh", ["-c", cmdStr], { stdio: "ignore", detached: true });
        child.on("error", (err) => debugError("notify: spawn error", err));
        child.unref();
      } else {
        // Fallback: plain osascript notification (non-interactive)
        const notif = `display notification ${shellQuote(message)} with title ${shellQuote(title)} subtitle ${shellQuote(subtitle)}`;
        debug(`notify: falling back to osascript: ${notif}`);
        const child = spawn("osascript", ["-e", notif], { stdio: "ignore", detached: true });
        child.on("error", (err) => debugError("notify: osascript spawn error", err));
        child.unref();
      }
    },

    async playAudio(filePath, onProcess) {
      debug(`playAudio: ${filePath}`);
      return new Promise<void>((resolve, reject) => {
        const proc = spawn("afplay", [filePath], { stdio: "ignore" });
        debug(`playAudio: afplay pid=${proc.pid}`);
        if (onProcess) onProcess(proc);
        proc.on("close", (code) => {
          debug(`playAudio: afplay pid=${proc.pid} exited with code=${code}`);
          // code null means killed by signal — user-initiated stop, not an error
          if (code === 0 || code === null) resolve();
          else reject(new Error(`afplay exited with code ${code}`));
        });
        proc.on("error", (err) => {
          debugError(`playAudio: afplay pid=${proc.pid} error`, err);
          reject(err);
        });
      });
    },

    isFocused(myPaneId) {
      debug(`isFocused: myPaneId='${myPaneId}' TMUX=${process.env.TMUX ?? "undefined"}`);
      try {
        // 1. Check if Ghostty is the frontmost app
        const frontmostApp = execSync(
          `osascript -e 'tell application "System Events" to get name of first application process whose frontmost is true'`,
          { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] },
        ).trim();
        debug(`isFocused: frontmostApp='${frontmostApp}'`);

        if (frontmostApp !== "Ghostty") {
          debug(`isFocused: Ghostty NOT focused → returning false`);
          return false;
        }

        // 2. Ghostty is focused — check if our tmux pane is the active one
        if (!myPaneId || !process.env.TMUX) {
          debug(`isFocused: Ghostty focused, no tmux — returning true`);
          return true;
        }

        const activePane = execSync(
          `tmux display-message -p -t '' '#{pane_id}'`,
          { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] },
        ).trim();
        debug(`isFocused: activePane='${activePane}' myPaneId='${myPaneId}' match=${activePane === myPaneId}`);
        return activePane === myPaneId;
      } catch (err) {
        debugError("isFocused: error detecting focus", err);
        // If we can't determine focus, assume focused (skip auto-play)
        return true;
      }
    },
  };
}

