/**
 * Platform abstraction for pi-speak extension.
 *
 * All OS-specific calls are isolated behind the Platform interface
 * so Linux and Windows implementations can be dropped in later.
 */

import { execSync, spawn, type ChildProcess } from "node:child_process";
import { shellQuote } from "./helpers.js";
import { debug, debugError } from "./debug.js";

export interface Platform {
  /** Send a system notification (non-interactive — no click action) */
  notify(title: string, subtitle: string, message: string): void;
  /** Play an MP3 file. Resolves when playback finishes. */
  playAudio(filePath: string, onProcess?: (proc: ChildProcess) => void): Promise<void>;
}

export function createPlatform(): Platform {
  switch (process.platform) {
    case "darwin":
      return createMacOSPlatform();
    default:
      return {
        notify: () => {},
        playAudio: async () => {},
      } as Platform;
  }
}

function createMacOSPlatform(): Platform {
  return {
    notify(title, subtitle, message) {
      debug(`notify: title="${title}" subtitle="${subtitle}" message="${message}"`);
      const notif = `display notification ${shellQuote(message)} with title ${shellQuote(title)} subtitle ${shellQuote(subtitle)}`;
      const child = spawn("osascript", ["-e", notif], { stdio: "ignore", detached: true });
      child.on("error", (err) => debugError("notify: osascript spawn error", err));
      child.unref();
    },

    async playAudio(filePath, onProcess) {
      debug(`playAudio: ${filePath}`);
      return new Promise<void>((resolve, reject) => {
        const proc = spawn("afplay", [filePath], { stdio: "ignore" });
        debug(`playAudio: afplay pid=${proc.pid}`);
        if (onProcess) onProcess(proc);
        proc.on("close", (code) => {
          debug(`playAudio: afplay pid=${proc.pid} exited with code=${code}`);
          if (code === 0 || code === null) resolve();
          else reject(new Error(`afplay exited with code ${code}`));
        });
        proc.on("error", (err) => {
          debugError(`playAudio: afplay pid=${proc.pid} error`, err);
          reject(err);
        });
      });
    },
  };
}

/**
 * pi-speak — Voice readback extension for Pi
 *
 * When the agent finishes a turn, this extension:
 *   1. Fires a macOS notification with session name + summary
 *   2. Registers alt+r (or configured shortcut) to replay / stop the last response
 *   3. Shows a status widget below the editor
 *
 * Settings: see ~/.config/pi-speak/config.json
 * API key: read from ~/.env (UNREAL_SPEECH_API_KEY) or process.env
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { createPlatform } from "./platform.js";
import { TTSPlayer } from "./tts.js";
import { loadConfig, initConfig } from "./config.js";
import { loadEnvKey, stripMarkdown, summarize } from "./helpers.js";
import { debug, debugError } from "./debug.js";

export default function (pi: ExtensionAPI) {
  const config = loadConfig();
  const platform = createPlatform();
  const player = new TTSPlayer(platform, config);

  // ── State ──────────────────────────────────────────────────────────────────

  let lastResponseText = "";
  let disabled = false;
  let sessionName = "";

  // ── Extract assistant text ────────────────────────────────────────────────

  function extractAssistantText(messages: any[]): string {
    for (let i = messages.length - 1; i >= 0; i--) {
      const msg = messages[i];
      if (msg?.role !== "assistant") continue;

      const textParts: string[] = [];
      for (const block of msg.content ?? []) {
        if (block.type === "text" && typeof block.text === "string") {
          textParts.push(block.text);
        }
      }

      if (textParts.length > 0) {
        return stripMarkdown(textParts.join("\n"));
      }
    }
    return "";
  }

  // ── Session start ─────────────────────────────────────────────────────────

  pi.on("session_start", async (_event, ctx) => {
    debug("=== session_start ===");

    // Capture session name for notifications
    sessionName = process.env.TMUX_PANE
      ? (() => {
          try {
            const { execSync } = await import("node:child_process");
            return execSync(
              `tmux display-message -p -t '${process.env.TMUX_PANE}' '#{session_name}'`,
              { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] },
            ).trim();
          } catch { return ""; }
        })()
      : "";

    // Create default config file if missing
    initConfig();

    // Clear stale audio cache from previous sessions
    player.clearCache();

    // Load API key from ~/.env (fallback to process.env)
    if (!process.env.UNREAL_SPEECH_API_KEY) {
      const fromEnv = loadEnvKey("UNREAL_SPEECH_API_KEY");
      if (fromEnv) {
        process.env.UNREAL_SPEECH_API_KEY = fromEnv;
      }
    }

    if (!process.env.UNREAL_SPEECH_API_KEY) {
      disabled = true;
      debug("session_start: NO API KEY — extension disabled");
      ctx.ui.notify(
        "speak: UNREAL_SPEECH_API_KEY not set — voice readback disabled. Add it to ~/.env",
        "warning",
      );
      ctx.ui.setWidget("speak", undefined);
      return;
    }

    debug("session_start: API key loaded, extension enabled");
    ctx.ui.setWidget("speak", ["🔊 " + config.shortcut + " read aloud"]);
  });

  // ── Agent end ─────────────────────────────────────────────────────────────

  pi.on("agent_end", async (event, ctx) => {
    debug("=== agent_end ===");
    if (disabled) {
      debug("agent_end: SKIPPED (disabled)");
      return;
    }

    const text = extractAssistantText(event.messages);
    debug(`agent_end: extracted text length=${text.length} preview="${text.slice(0, 80)}"`);
    if (!text) {
      debug("agent_end: no assistant text — skipping");
      return;
    }

    // Clear cached audio from previous response (conversation moved on)
    if (text !== lastResponseText) {
      debug(`agent_end: new response (${text.length} chars), clearing old cache`);
      player.clearCache();
    }
    lastResponseText = text;
    ctx.ui.setWidget("speak", ["🔊 Ready  " + config.shortcut + " replay"]);

    // Fire notification with session name + summary
    const summary = summarize(text);
    const label = sessionName ? `${sessionName}` : "Pi";
    platform.notify("Pi ✓", label, summary);
    debug(`agent_end: notification sent — label="${label}" summary="${summary}"`);
  });

  // ── Shortcut: alt+r — replay / stop ───────────────────────────────────────

  pi.registerShortcut(config.shortcut, {
    description: "Replay last response aloud / stop current playback",
    handler: (ctx) => {
      debug(`=== shortcut: ${config.shortcut} pressed ===`);
      if (disabled) {
        debug(`shortcut: SKIPPED (disabled)`);
        return;
      }

      if (player.playing) {
        debug(`shortcut: STOP (was playing)`);
        player.stop();
        ctx.ui.setWidget("speak", ["🔊 Ready  " + config.shortcut + " replay"]);
        return;
      }

      if (!lastResponseText) {
        debug(`shortcut: no response to replay`);
        ctx.ui.notify("speak: no response to replay yet", "info");
        return;
      }

      debug(`shortcut: REPLAY (text length=${lastResponseText.length})`);
      try {
        player.speak(lastResponseText, ctx.ui);
      } catch (err) {
        debugError("shortcut: speak() threw", err);
        ctx.ui.notify(`speak: replay error — ${err instanceof Error ? err.message : String(err)}`, "error");
      }
    },
  });
}

